<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">                WHEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;👎&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> THEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span>
